data.syntax:
erDiagram
    PATIENT ||--o{ VISIT : attends
    PHYSICIAN ||--o{ VISIT : conducts
    VISIT ||--o{ LAB_RESULT : produces
    PATIENT ||--o{ PRESCRIPTION : receives
    PRESCRIPTION }o--|| DRUG : references
    PATIENT {
        int patient_id PK
        string name
        date dob
        string gender
    }
    VISIT {
        int visit_id PK
        date visit_date
        string chief_complaint
    }
    PHYSICIAN {
        int physician_id PK
        string name
        string specialty
    }
    LAB_RESULT {
        int result_id PK
        string test_name
        string value
        string unit
    }
    PRESCRIPTION {
        int rx_id PK
        string dosage
        date start_date
    }
    DRUG {
        int drug_id PK
        string name
        string class
    }
